const App = () => {
  const courseFso = {
    names: 'Half Stack application development ',
    nameOfCouse: 'Half Stack application development',
    parts: [
      {
        name: 'Fundamentals of React',
        exercises: 10,
      },
      {
        name: 'Using props to pass data',
        exercises: 7,
      },
      {
        name: 'State of a component',
        exercises: 14,
      },
    ]
  }
  return (
    <div>
      <Header courseName={courseFso.nameOfCouse} />
      <Content parts={courseFso.parts} />
      <Total names={courseFso.names} totalParts={courseFso.parts} />
    </div>
  )
}

const Header = (props) => {
  return (
    <h1>{props.courseName}</h1>
  )
}
const Part = (props) => {
  return (
    <p>
      {props.part.name} {props.part.exercises}
    </p>
  )
}

const Content = props => (
  <>
    <Part part={props.parts[0]} />
    <Part part={props.parts[1]} />
    <Part part={props.parts[2]} />
  </>
)
const Total = (props) => {
  return (
    <p>
      {props.names}
      {props.totalParts.reduce((total, part) => part.exercises + total, 0)}
    </p>

  )
}

export default App
